def test_layers_kwarg_wraps_the_backend():
    from functools import partial

    from storix._sync import SandboxLayer

    inner = MemoryBackend()
    inner.make_dir(P('/jail'), parents=False)
    fs = Storix(inner, layers=[partial(SandboxLayer, root='/jail')])

    fs.touch('/a.txt')
    assert inner.exists(P('/jail/a.txt'))


def test_with_layer_returns_a_new_wrapped_session():
    from functools import partial

    from storix._sync import SandboxLayer

    inner = MemoryBackend()
    inner.make_dir(P('/jail'), parents=False)

    fs = Storix(inner)
    jailed = fs.with_layer(partial(SandboxLayer, root='/jail'))

    jailed.touch('/a.txt')
    assert inner.exists(P('/jail/a.txt'))
    assert fs.exists('/jail/a.txt')  # original session untouched


def test_chroot_jails_a_new_session(fs: Storix):
    fs.mkdir('/jail')
    fs.echo(b'secret', '/top-secret.txt')

    jailed = fs.chroot('/jail')
    jailed.touch('/inside.txt')

    assert fs.exists('/jail/inside.txt')  # same store underneath
    assert not jailed.exists('/top-secret.txt')  # cannot see above
    assert not jailed.exists('/../top-secret.txt')  # cannot escape
    assert str(fs.pwd()) == '/'  # original untouched


