def test_context_manager_closes_backend():
    class _ClosingBackend(MemoryBackend):
        closed = False

        def close(self) -> None:
            self.closed = True

    backend = _ClosingBackend()
    with Storix(backend) as fs:
        fs.touch('/a.txt')
    assert backend.closed


def test_predicates(fs: Storix):
    fs.touch('/a.txt')
    fs.mkdir('/d')
    assert fs.isfile('/a.txt')
    assert not fs.isfile('/d')
    assert not fs.isfile('/nope')
    assert fs.isdir('/d')
    assert not fs.isdir('/a.txt')
    assert not fs.isdir('/nope')
